WITH symbols(sym) AS (SELECT * FROM (VALUES ('AGMH'),('ALACU'),('AMHC'),('ANDA'),('APEX'),('BCLI'),('BHAT'),('BIOC'),('BKYI'),('BLFS'),('BOSC'),('BOTJ'),('BWEN'),('CBAT'),('CCCL'),('CDMOP'),('CEMI'),('CFBK'),('CFFA'),('CLRB'),('CORV'),('CPAAU'),('CPAH'),('CUBA'),('CVV'),('DZSI'),('ELSE'),('EXPC'),('EYEG'),('FAMI'),('FNCB'),('FSBW'),('FTFT'),('GDYN'),('GLG'),('GRNVU'),('GTEC'),('HCCOU'),('HNNA'),('HQI'),('HRTX'),('IDEX'),('IGIC'),('IOTS'),('ISNS'),('ITI'),('LACQ'),('MBCN'),('MBNKP'),('MCEP'),('MLND'),('MMAC'),('MNCLU'),('MNPR'),('NVEE'),('NXTD'),('OPOF'),('OPTT'),('ORGO'),('ORSNU'),('OTEL'),('PBFS'),('PBTS'),('PCSB'),('PECK'),('PEIX'),('PFIE'),('PLIN'),('POPE'),('QRHC'),('SES'),('SHSP'),('SNSS'),('SSNT'),('STKS'),('TGLS'),('TMSR'),('VERB'),('VMD'),('VRRM'),('VTIQW'),('VVPR'),('WHLM'),('WHLR'),('XBIOW'),('XPEL')))
), existing AS (
  SELECT sym FROM symbols
  WHERE sym IN (SELECT table_name FROM information_schema.tables)
), unioned AS (
  SELECT e.sym AS Symbol, t.Date, t.High, t.Low
  FROM existing e
  JOIN LATERAL (
    SELECT Date, High, Low FROM (SELECT * FROM (SELECT * FROM "AGMH") ) WHERE 1=0
  ) t ON FALSE
)
SELECT * FROM unioned LIMIT 0;

